(window.webpackJsonp=window.webpackJsonp||[]).push([[51],{678:function(n,r){n.exports='\x3c!-- \r\ntitle: 12-Linux常用网络工具\r\nsort: \r\n--\x3e \r\n## Curl\r\n\r\n发送网络请求\r\n\r\n```bash\r\ncurl https://www.baidu.com/\r\n# 下载\r\ncurl https://www.baidu.com/ -o 1.html\r\n# 静音模式，不输出任何东西\r\ncurl https://www.baidu.com/ -s \r\n# 指定请求头\r\ncurl -H -d -X\r\n# 设置头、post方法以及date\r\ncurl https://www.baidu.com/?name ==\'kiki\' -H "A:B" -X POST -d "age = 22"\r\n```\r\n\r\n'}}]);